def predict(triples: list[Triple]) -> str:
    # Group triples by subject for better sentence construction
    subject_triples = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    sentences = []

    for subject, triples_list in subject_triples.items():
        # Handle special cases with natural language patterns
        demonym_triple = next((t for t in triples_list if t.predicate == "demonym"), None)
        if demonym_triple:
            # "The people of Texas are known as Texans."
            subject_clean = demonym_triple.subject.replace(", Texas", "") if ", Texas" in demonym_triple.subject else demonym_triple.subject
            sentences.append(f"The people of {subject_clean} are known as {demonym_triple.object}.")
            continue

        language_triple = next((t for t in triples_list if t.predicate == "language"), None)
        if language_triple:
            # "Spanish is spoken in Texas."
            # Remove "language" suffix if present for more natural phrasing
            obj = triple.object.replace(" language", "") if " language" in triple.object else triple.object
            sentences.append(f"{obj} is spoken in {subject}.")
            continue

        country_triple = next((t for t in triples_list if t.predicate == "country"), None)
        if country_triple:
            # "Punjab is located in Pakistan." (more natural and consistent with location phrasing)
            sentences.append(f"{subject} is located in {country_triple.object}.")
            continue

        # Handle cityServed with natural phrasing
        city_served_triple = next((t for t in triples_list if t.predicate == "cityServed"), None)
        if city_served_triple:
            # "Aarhus Airport serves the city of Aarhus, Denmark."
            sentences.append(f"{subject} serves the city of {city_served_triple.object}.")
            continue

        # Handle other common cases naturally
        for triple in triples_list:
            if triple.predicate == "elevationAboveTheSeaLevel":
                sentences.append(f"{subject} is located at an elevation of {triple.object} meters above sea level.")
            elif triple.predicate == "location":
                sentences.append(f"{subject} is located in {triple.object}.")
            elif triple.predicate == "operatingOrganisation":
                sentences.append(f"{subject} is operated by {triple.object}.")
            elif triple.predicate == "runwayLength":
                sentences.append(f"{subject} has a runway that is {triple.object} meters long.")
            elif triple.predicate == "runwayName":
                sentences.append(f"{subject}'s runway name is {triple.object}.")
            elif triple.predicate == "isPartOf":
                sentences.append(f"{subject} is part of {triple.object}.")
            elif triple.predicate == "icaoLocationIdentifier":
                sentences.append(f"{subject} has the ICAO code {triple.object}.")
            elif triple.predicate == "iataLocationIdentifier":
                sentences.append(f"{subject} has the IATA code {triple.object}.")
            elif triple.predicate == "elevationAboveTheSeaLevelInFeet":
                sentences.append(f"{subject} is at an elevation of {triple.object} feet above sea level.")
            elif triple.predicate == "elevationAboveTheSeaLevelInMetres":
                sentences.append(f"{subject} is at an elevation of {triple.object} metres above sea level.")
            elif triple.predicate == "nativeName":
                sentences.append(f"{subject} is also known as {triple.object}.")
            elif triple.predicate == "owner":
                sentences.append(f"{subject} is owned by {triple.object}.")
            elif triple.predicate == "capital":
                sentences.append(f"The capital of {subject} is {triple.object}.")
            elif triple.predicate == "officialLanguage":
                sentences.append(f"The official language of {subject} is {triple.object}.")
            elif triple.predicate == "largestCity":
                sentences.append(f"The largest city in {subject} is {triple.object}.")
            elif triple.predicate == "mayor":
                sentences.append(f"The mayor of {subject} is {triple.object}.")
            elif triple.predicate == "runwaySurfaceType":
                sentences.append(f"{subject} has a runway surface type of {triple.object}.")
            elif triple.predicate == "1stRunwayLengthFeet":
                sentences.append(f"{subject} has a first runway that is {triple.object} feet long.")
            elif triple.predicate == "1stRunwaySurfaceType":
                sentences.append(f"{subject} has a first runway with surface type {triple.object}.")
            elif triple.predicate == "3rdRunwayLengthFeet":
                sentences.append(f"{subject} has a third runway that is {triple.object} feet long.")
            elif triple.predicate == "1stRunwayNumber":
                sentences.append(f"{subject} has a first runway numbered {triple.object}.")
            elif triple.predicate == "4thRunwayLengthFeet":
                sentences.append(f"{subject} has a fourth runway that is {triple.object} feet long.")
            elif triple.predicate == "4thRunwaySurfaceType":
                sentences.append(f"{subject} has a fourth runway with surface type {triple.object}.")
            elif triple.predicate == "5thRunwayNumber":
                sentences.append(f"{subject} has a fifth runway numbered {triple.object}.")
            elif triple.predicate == "5thRunwaySurfaceType":
                sentences.append(f"{subject} has a fifth runway with surface type {triple.object}.")
            elif triple.predicate == "countySeat":
                sentences.append(f"The county seat of {subject} is {triple.object}.")
            elif triple.predicate == "chief":
                sentences.append(f"The chief of {subject} is {triple.object}.")
            elif triple.predicate == "foundedBy":
                sentences.append(f"{subject} was founded by {triple.object}.")
            elif triple.predicate == "postalCode":
                sentences.append(f"{subject} has the postal code {triple.object}.")
            elif triple.predicate == "areaCode":
                sentences.append(f"{subject} has the area code {triple.object}.")
            elif triple.predicate == "foundingYear":
                sentences.append(f"{subject} was founded in {triple.object}.")
            elif triple.predicate == "ceremonialCounty":
                sentences.append(f"{subject} is in the ceremonial county of {triple.object}.")
            elif triple.predicate == "administrativeArrondissement":
                sentences.append(f"{subject} is in the administrative arrondissement of {triple.object}.")
            elif triple.predicate == "hubAirport":
                sentences.append(f"{subject} has its hub at {triple.object}.")
            elif triple.predicate == "headquarter":
                sentences.append(f"{subject} has its headquarters at {triple.object}.")
            elif triple.predicate == "jurisdiction":
                sentences.append(f"{subject} has jurisdiction over {triple.object}.")
            elif triple.predicate == "regionServed":
                sentences.append(f"{subject} serves the region of {triple.object}.")
            elif triple.predicate == "leader":
                sentences.append(f"The leader of {subject} is {triple.object}.")
            elif triple.predicate == "population":
                sentences.append(f"{subject} has a population of {triple.object}.")
            elif triple.predicate == "area":
                sentences.append(f"{subject} has an area of {triple.object} square kilometers.")
            else:
                sentences.append(f"{subject} has a {triple.predicate} of {triple.object}.")

    # Combine related triples into complex sentences when possible
    if len(sentences) > 1:
        # Look for airport-related triples that can be combined
        airport_sentences = []
        other_sentences = []

        for sentence in sentences:
            # Check if sentence is about an airport (contains "Airport" in subject)
            if any(triple.subject.endswith("Airport") for triple in triples if triple.subject in sentence):
                airport_sentences.append(sentence)
            else:
                other_sentences.append(sentence)

        # If we have multiple airport sentences, try to combine them
        if len(airport_sentences) > 1:
            # Extract the main airport subject from the first sentence
            main_airport = None
            for triple in triples:
                if triple.subject.endswith("Airport"):
                    main_airport = triple.subject
                    break

            if main_airport:
                # Create a complex sentence combining all airport information
                combined_parts = []

                # First part: city served
                city_served = None
                for triple in triples:
                    if triple.predicate == "cityServed":
                        city_served = triple.object
                        break

                # Elevation
                elevation = None
                elevation_unit = None
                for triple in triples:
                    if triple.predicate == "elevationAboveTheSeaLevel":
                        elevation = triple.object
                        elevation_unit = "meters"
                        break
                    elif triple.predicate == "elevationAboveTheSeaLevelInMetres":
                        elevation = triple.object
                        elevation_unit = "metres"
                        break
                    elif triple.predicate == "elevationAboveTheSeaLevelInFeet":
                        elevation = triple.object
                        elevation_unit = "feet"
                        break

                # Runway info
                runway_info = []
                for triple in triples:
                    if triple.predicate == "runwayName":
                        runway_info.append(f"runway {triple.object}")
                    elif triple.predicate == "runwayLength":
                        runway_info.append(f"runway of {triple.object} meters")
                    elif triple.predicate == "1stRunwayLengthFeet":
                        runway_info.append(f"first runway of {triple.object} feet")
                    elif triple.predicate == "1stRunwaySurfaceType":
                        runway_info.append(f"first runway with surface type {triple.object}")
                    elif triple.predicate == "2ndRunwaySurfaceType":
                        runway_info.append(f"second runway with surface type {triple.object}")
                    elif triple.predicate == "3rdRunwaySurfaceType":
                        runway_info.append(f"third runway with surface type {triple.object}")
                    elif triple.predicate == "4thRunwayLengthFeet":
                        runway_info.append(f"fourth runway of {triple.object} feet")
                    elif triple.predicate == "4thRunwaySurfaceType":
                        runway_info.append(f"fourth runway with surface type {triple.object}")
                    elif triple.predicate == "5thRunwayNumber":
                        runway_info.append(f"fifth runway numbered {triple.object}")
                    elif triple.predicate == "5thRunwaySurfaceType":
                        runway_info.append(f"fifth runway with surface type {triple.object}")
                    elif triple.predicate == "runwaySurfaceType":
                        runway_info.append(f"runway surface type {triple.object}")

                # Build complex sentence
                complex_sentence = main_airport
                if city_served:
                    complex_sentence += f" serves the city of {city_served}"

                if elevation is not None:
                    if city_served:
                        complex_sentence += " which"
                    else:
                        complex_sentence += " which"
                    complex_sentence += f" is located at an elevation of {elevation} {elevation_unit} above sea level"

                if runway_info:
                    if elevation is not None or city_served:
                        complex_sentence += " and"
                    else:
                        complex_sentence += " which"
                    complex_sentence += " has " + ", ".join(runway_info)

                complex_sentence += "."
                airport_sentences = [complex_sentence]

        sentences = airport_sentences + other_sentences

    return " ".join(sentences).strip()

